<div class="d-flex justify-content-between align-items-center mb-3"><h1 class="page-title h3 mb-0"><?= e($title) ?></h1><a class="btn btn-outline-secondary" href="<?= e(url('index.php?page=produk')) ?>">Kembali</a></div><div class="card enterprise-card"><div class="card-body p-4"><form method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?= e(csrf_token()) ?>"><div class="row g-3"><div class="col-lg-8"><div class="row g-3"><div class="col-md-4"><label class="form-label">Kode Produk</label><input class="form-control" name="kode_produk" value="<?= e($row['kode_produk'] ?? '') ?>" required></div><div class="col-md-4"><label class="form-label">Barcode</label><input class="form-control" name="barcode" value="<?= e($row['barcode'] ?? '') ?>" placeholder="Opsional / scan barcode"></div><div class="col-md-4"><label class="form-label">Status</label><select class="form-select" name="status"><option value="aktif" <?= (($row['status'] ?? 'aktif') === 'aktif')?'selected':'' ?>>Aktif</option><option value="nonaktif" <?= (($row['status'] ?? '') === 'nonaktif')?'selected':'' ?>>Nonaktif</option></select></div><div class="col-12"><label class="form-label">Nama Produk</label><input class="form-control" name="nama_produk" value="<?= e($row['nama_produk'] ?? '') ?>" required></div><div class="col-md-4"><label class="form-label">Kategori</label><select class="form-select" name="kategori_id" required><?php foreach($categories as $c): ?><option value="<?= e($c['id']) ?>" <?= (($row['kategori_id'] ?? '') == $c['id']) ? 'selected' : '' ?>><?= e($c['nama_kategori']) ?></option><?php endforeach; ?></select></div><div class="col-md-4"><label class="form-label">Satuan</label><select class="form-select" name="satuan_id" required><?php foreach($units as $u): ?><option value="<?= e($u['id']) ?>" <?= (($row['satuan_id'] ?? '') == $u['id']) ? 'selected' : '' ?>><?= e($u['nama_satuan']) ?></option><?php endforeach; ?></select></div><div class="col-md-4"><label class="